class Solution:
    def kthSmallest(self, mat, k):
        import heapq
        # merge row by row keeping top-k sums
        sums = [0]
        for row in mat:
            new_sums = []
            heap = []
            for s in sums:
                heapq.heappush(heap, (s + row[0], 0, s))
            while heap and len(new_sums) < k:
                val, j, prev = heapq.heappop(heap)
                new_sums.append(val)
                if j + 1 < len(row):
                    heapq.heappush(heap, (prev + row[j+1], j+1, prev))
            sums = new_sums
        return sums[k-1]

