var kthSmallest = function(mat, k) {
    // MinHeap helper
    class MinHeap {
        constructor() { this.h = []; }
        push(item) {
            this.h.push(item);
            let i = this.h.length - 1;
            while (i > 0) {
                const p = (i - 1) >> 1;
                if (this.h[p][0] <= this.h[i][0]) break;
                [this.h[p], this.h[i]] = [this.h[i], this.h[p]];
                i = p;
            }
        }
        pop() {
            const top = this.h[0];
            const last = this.h.pop();
            if (this.h.length > 0) {
                this.h[0] = last;
                let i = 0;
                while (true) {
                    let s = i, l = 2*i+1, r = 2*i+2;
                    if (l < this.h.length && this.h[l][0] < this.h[s][0]) s = l;
                    if (r < this.h.length && this.h[r][0] < this.h[s][0]) s = r;
                    if (s === i) break;
                    [this.h[i], this.h[s]] = [this.h[s], this.h[i]];
                    i = s;
                }
            }
            return top;
        }
        get size() { return this.h.length; }
    }
    let sums = [0];
    for (const row of mat) {
        const heap = new MinHeap();
        for (const s of sums) heap.push([s + row[0], 0, s]);
        const newSums = [];
        while (heap.size > 0 && newSums.length < k) {
            const [val, j, prev] = heap.pop();
            newSums.push(val);
            if (j + 1 < row.length) heap.push([prev + row[j+1], j+1, prev]);
        }
        sums = newSums;
    }
    return sums[k-1];
};
